        for (int i = 0; i < len && i < 2; i++)
            packed[i] = Long_val(Field(v_packed, i));
        g_effect_wall_write_reset_walls(packed, len);
    }
    CAMLreturn(Val_unit);
}

/* -- Wall: C entry point ------------------------------------------------ */

void cd_ox_reset_walls(void)
{
    cd_ox_require_ready("cd_ox_reset_walls");
    CAMLparam0();
    caml_callback(*g_reset_walls, Val_unit);
    CAMLreturn0;
}

