        g_fetch_wall_data(Int_val(v_segnum), Int_val(v_sidenum), buf);
    v_result = caml_alloc(8, 0);
    for (int i = 0; i < 8; i++)
        Store_field(v_result, i, Val_long(buf[i]));
    CAMLreturn(v_result);
}

