//do whatever needs to be done when a player dies in multiplayer

void DoGameOver()
{
	time_out_value = timer_get_approx_seconds() + i2f(60 * 5);
	nm_messagebox1(TXT_GAME_OVER, DoEndLevelScoreGlitzPoll, 1, TXT_OK, "");

